import csv
import itertools
import re
from abc import ABC, abstractmethod
from functools import reduce
from operator import itemgetter

from .mapping import DoubleMapping


class ClassificationCode(ABC):
    """Data structure to quickly get the correspondences between a class name and its identifier"""

    def __init__(self, path_delimiter="/"):
        """
        :param path_delimiter: the character used to split the classes in the classification paths
        """
        self.path_delimiter = path_delimiter

    @classmethod
    def open(cls, source, delimiter=";", path_delimiter="/"):
        classification_code = cls(path_delimiter=path_delimiter)
        regex_name = r"\w+"
        regex_identifier = r"\d+"
        reader = csv.reader(source, delimiter=delimiter)
        for row in reader:
            if re.match(regex_name, row[0]) and re.match(regex_identifier, row[1]):
                classification_code[row[0]] = int(row[1])
        return classification_code

    @classmethod
    def parse_file(cls, csv_path, delimiter=";", path_delimiter="/"):
        """Parse a .csv file located at "csvPath" and return a new ClassificationCode instance"""
        with open(csv_path, newline="") as csv_file:
            return cls.open(
                csv_file, delimiter=delimiter, path_delimiter=path_delimiter
            )

    def save(self, destination, delimiter=";"):
        writer = csv.writer(destination, delimiter=delimiter)
        for class_name, identifier in sorted(self, key=itemgetter(1, 0)):
            writer.writerow([class_name, identifier])

    def write_file(self, csv_path, delimiter=";"):
        """Write to a .csv file located at "csvPath" containing this classification code"""
        with open(csv_path, mode="w", newline="") as csv_file:
            self.save(csv_file, delimiter=delimiter)

    @classmethod
    def from_dict(cls, dictionary):
        path_delimiter = dictionary["delimiter"]
        classification_code = cls(path_delimiter=path_delimiter)
        for key, value in dictionary["codes"].items():
            classification_code[key] = value
        return classification_code

    def to_dict(self):
        return {
            "delimiter": self.path_delimiter,
            "codes": dict(self),
        }

    def join(self, paths):
        """Concatenates the paths "paths", using "pathDelimiter"
        pathDelimiter = "/"
        paths = ["A", "B", "C"] => "A/B/C"
        """
        return self.path_delimiter.join([path for path in paths if path])

    def split(self, path):
        """Splits "path" with the object path delimiter
        pathDelimiter = "/"
        path = "A/B/C" => ["A", "B", "C"]
        """
        return path.split(self.path_delimiter)

    @staticmethod
    def list_intersection(list_a, list_b):
        """Computes a list while intersection:
        [A, B, C], [A, D, C] => [A]
        """
        return [
            A or B
            for A, B in itertools.takewhile(
                lambda x: x[0] == x[1] or not x[0] or not x[1], zip(list_a, list_b)
            )
        ]

    def common_path(self, paths):
        """Returns the common path of the list of paths "paths"
        ["A/B/C", "A/D/C", "A"] => "A"
        """
        splitted_path = [self.split(path) for path in paths]
        return self.join(
            reduce(
                ClassificationCode.list_intersection,
                splitted_path,
                [""] * max([len(path) for path in splitted_path] or [0]),
            )
        )

    def get_identifier_from_path(self, class_path):
        """Return the identifier corresponding to "classPath"
        With classPath="A/B/C", test recursively to find the identifier for "A/B/C", "A/B" and "A"
        """
        class_names = self.split(class_path)
        while class_names:
            class_name = self.join(class_names)
            if class_name in self:
                return self.get_identifier(class_name)
            class_names = class_names[:-1]
        return None

    def contains_node(self, node_name):
        """Indicate if the data structure contains the node "nodeName"
        With nodeName="B" and self={"A/B/C": 1}, returns True
        """
        for class_name, _ in self:
            if node_name in self.split(class_name):
                return True
        return False

    def get_identifiers_from_node(self, node_name):
        """Return a set of identifiers corresponding to the class names that contain "nodeName"
        With nodeName="B" and self={"A/B/C": 1}, returns {1}
        """
        return {
            identifier
            for className, identifier in self
            if node_name in self.split(className)
        }

    def get_identifier_from_paths(self, paths):
        """Return the identifier corresponding to the concatenation of the elements of "paths" """
        return self[self.join(paths)]

    def get_identifiers_from_prefix(self, prefix):
        """Return the identifier corresponding to the concatenation of the elements of "paths" """
        # TODO: Use a tree structure to make this O(log(len(self)))
        return set(
            identifier
            for class_name, identifier in self
            if class_name.startswith(prefix)
        )

    @abstractmethod
    def _add(self, class_name, identifier):
        pass

    def add(self, class_name, identifier):
        """Add the className and its identifier to the data structure"""
        if class_name in self:
            raise RuntimeError("{} is already present".format(class_name))
        return self._add(class_name, identifier)

    @abstractmethod
    def get_identifier(self, class_name):
        """Return the identifier corresponding to "className" """

    @abstractmethod
    def get_class_names(self, identifier):
        """Return the list of class names corresponding to "identifier" """

    @abstractmethod
    def contains_class_name(self, class_name):
        """Indicate if the data structure contains the class name "className" """

    @abstractmethod
    def contains_identifier(self, identifier):
        """Indicate if the data structure contains the identifier "identifier" """

    @abstractmethod
    def remove_with_class_name(self, class_name):
        """Remove the pair (className, identifier) knowing "className" """

    @abstractmethod
    def remove_with_identifier(self, identifier):
        """Remove all the pairs (className, identifier) knowing "identifier" """

    @abstractmethod
    def __len__(self):
        """Return the number of pairs (className, identifier) contained in the data structure"""

    @abstractmethod
    def __iter__(self):
        """Return the successive pairs (className, identifier), unordered"""

    def __eq__(self, other):
        return self.__dict__ == other.__dict__

    def __contains__(self, class_name):
        return self.contains_class_name(class_name)

    def __getitem__(self, class_name):
        return self.get_identifier(class_name)

    def __setitem__(self, class_name, identifier):
        self.add(class_name, identifier)

    @classmethod
    def common_args(cls, parser):
        parser.add_argument(
            "--path_delimiter",
            help="Delimiter to use in the paths of the classification code",
            default="/",
        )

    @classmethod
    def common_args_file(cls, parser):
        parser.add_argument(
            "--input_delimiter",
            help="Delimiter to use to parse the input .csv file",
            default=";",
        )

    namespace = "code"


class SimpleClassificationCode(ClassificationCode):
    def __init__(self, path_delimiter="/"):
        """Create an instance of ClassificationCode to quickly get the correspondances between a class name and its
        identifier
        """
        super(SimpleClassificationCode, self).__init__(path_delimiter=path_delimiter)
        self.code = {}

    def _add(self, class_name, identifier):
        """Add the className and its identifier to the data structure"""
        self.code[class_name] = identifier

    def get_identifier(self, class_name):
        """Return the identifier corresponding to "className" """
        return self.code[class_name]

    def get_class_names(self, identifier):
        """Return the list of class names corresponding to "identifier" """
        return {
            class_name
            for class_name, class_id in self.code.items()
            if class_id == identifier
        }

    def contains_class_name(self, class_name):
        """Indicate if the data structure contains the class name "className" """
        return class_name in self.code

    def contains_identifier(self, identifier):
        """Indicate if the data structure contains the identifier "identifier" """
        return identifier in self.code.values()

    def remove_with_class_name(self, class_name):
        """Remove the pair (className, identifier) knowing "className" """
        del self.code[class_name]

    def remove_with_identifier(self, identifier):
        """Remove all the pairs (className, identifier) knowing "identifier" """
        self.code = {
            class_name: class_id
            for class_name, class_id in self.code.items()
            if class_id == identifier
        }

    def __len__(self):
        """Return the number of pairs (className, identifier) contained in the data structure"""
        return len(self.code)

    def __iter__(self):
        """Return the successive pairs (className, identifier), unordered"""
        return iter(self.code.items())


class DoubleClassificationCode(ClassificationCode):
    def __init__(self, path_delimiter="/"):
        super(DoubleClassificationCode, self).__init__(path_delimiter=path_delimiter)
        self.code = DoubleMapping()

    def _add(self, class_name, identifier):
        """Add the className and its identifier to the data structure"""
        self.code.add_couple(class_name, identifier)

    def get_identifier(self, class_name):
        """Return the identifier corresponding to "className" """
        return self.code.get_y(class_name)

    def get_class_name(self, identifier):
        """Return the class name corresponding to "identifier" """
        return self.code.get_x(identifier)

    def get_class_names(self, identifier):
        """Return the list of class names corresponding to "identifier" """
        return (
            {self.get_class_name(identifier)}
            if self.contains_identifier(identifier)
            else set()
        )

    def contains_class_name(self, class_name):
        """Indicate if the data structure contains the class name "className" """
        return self.code.contains_x(class_name)

    def contains_identifier(self, identifier):
        """Indicate if the data structure contains the identifier "identifier" """
        return self.code.contains_y(identifier)

    def remove_with_class_name(self, class_name):
        """Remove the pair (className, identifier) knowing "className" """
        self.code.remove_with_x(class_name)

    def remove_with_identifier(self, identifier):
        """Remove the pair (className, identifier) knowing "identifier" """
        self.code.remove_with_y(identifier)

    def __len__(self):
        """Return the number of pairs (className, identifier) contained in the data structure"""
        return len(self.code)

    def __iter__(self):
        """Return the successive pairs (className, identifier), unordered"""
        return iter(self.code)
